// Decodifica el JWT del header Authorization para obtener el user_id
const headers = $input.first().json.headers || {};
const authHeader = (headers.authorization || headers.Authorization || '').toString();
const token = authHeader.replace(/^Bearer\s+/i, '').trim();

if (!token) {
  throw new Error('Authorization token requerido');
}

const parts = token.split('.');
if (parts.length !== 3) {
  throw new Error('Formato de token inválido');
}

try {
  const base64 = parts[1].replace(/-/g, '+').replace(/_/g, '/');
  const padding = '='.repeat((4 - base64.length % 4) % 4);
  const payload = JSON.parse(Buffer.from(base64 + padding, 'base64').toString('utf8'));
  const userId = payload.sub || payload.id || payload.user_id || payload.userId;
  if (!userId) throw new Error('user_id no encontrado en el token');
  return [{ json: { user_id: String(userId) } }];
} catch (e) {
  throw new Error('Error al decodificar token: ' + e.message);
}

// Devuelve array de notas (o array vacío si no hay resultados)
const items = $input.all();

// Si el único item es un error de Postgres, lanzarlo
if (items.length === 1 && items[0].json.error) {
  throw new Error('Error en base de datos: ' + (items[0].json.error?.message || String(items[0].json.error)));
}

const notes = items
  .map(i => i.json)
  .filter(n => n.id != null);

return [{ json: notes }];
